// Dijkstra's SPF Algorithm for OSPF
// Input: Graph G(V,E) with costs, Source router s
// Output: Shortest path tree (SPT)

INITIALIZE:
 SPT = empty set // Shortest Path Tree
 candidate_set = empty priority queue // Min-heap by cost
 distance[] = infinity for all vertices
 parent[] = null for all vertices

SET distance[s] = 0
INSERT (s, 0) into candidate_set

WHILE candidate_set is not empty:
 // Extract minimum cost vertex
 (u, dist_u) = EXTRACT_MIN(candidate_set)

 // Add to SPT
 ADD u to SPT

 // Examine neighbors of u
 FOR each neighbor v of u:
 IF v not in SPT THEN:
 // Calculate new cost through u
 new_cost = distance[u] + cost(u, v)

 // If better path found
 IF new_cost < distance[v] THEN:
 distance[v] = new_cost
 parent[v] = u
 INSERT (v, new_cost) into candidate_set

// Build routing table from parent[]
FOR each vertex v in SPT:
 IF parent[v] != null THEN:
 add route to v via parent[v] with cost distance[v]

// Recalculate on LSA changes:
ON LSA_CHANGE:
 UPDATE affected vertices in candidate_set
 REPEAT algorithm from current SPT state

// OSPF Hello Protocol

// Hello Packet Structure:
// - Network Mask
// - Hello Interval (10s broadcast, 30s point-to-point)
// - Options (E-bit for stub areas, N-bit for NSSA)
// - Router Priority
// - Dead Interval (4 × Hello = 40s or 120s)
// - DR, BDR
// - Neighbor List (RIDs of bidirectional neighbors)

SEND_HELLO():
 packet = CREATE_HELLO()
 packet.source = local_router_id
 packet.interface = outgoing_interface
 packet.mask = interface_subnet_mask
 packet.options = enabled_options
 packet.priority = interface_priority
 packet.dr = current_dr
 packet.bdr = current_bdr
 packet.neighbors = list_of_bidirectional_neighbors
 BROADCAST(packet)

RECEIVE_HELLO(packet):
 // Validate packet
 IF packet.hello_interval != local_hello_interval THEN:
 DISCARD packet
 IF packet.dead_interval != local_dead_interval THEN:
 DISCARD packet

 // Check if sender is in neighbor list
 IF local_router_id NOT IN packet.neighbors THEN:
 // Bidirectional not yet established
 ADD packet.source to neighbor_list
 TRANSITION neighbor to Init state
 ELSE:
 // Bidirectional confirmed
 TRANSITION neighbor to 2-Way state
 START/RESTART dead_timer for neighbor

NEIGHBOR_TIMEOUT():
 // Dead timer expired
 REMOVE neighbor from neighbor_list
 TRANSITION neighbor to Down state
 TRIGGER SPF recalculation if adjacency existed
